#include <stdio.h>
#include <stdlib.h>
#define MAX 100005

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &M);
        int *arr = (int*)malloc(M * sizeof(int));
        for (int i = 0; i < M; i++) {
            scanf("%d", &arr[i]);
        }
        long long ans = 0;
        while (M > 1) {
            qsort(arr, M, sizeof(int), compare);
            int a = arr[0], b = arr[1];
            ans += a + b;
            arr[0] = a + b;
            for (int i = 1; i < M - 1; i++) {
                arr[i] = arr[i + 1];
            }
            M--;
        }
        printf("%lld\n", ans);
        free(arr);
    }
    return 0;
}

