#include <iostream>
#include <queue>
using namespace std;

int main() {
    int T;
    cin >> T;
    while (T--) {
        int M;
        cin >> M;
        priority_queue<int, vector<int>, greater<int>> pq;
        for (int i = 0; i < M; i++) {
            int x;
            cin >> x;
            pq.push(x);
        }
        long long ans = 0;
        while (pq.size() > 1) {
            int a = pq.top();
            pq.pop();
            int b = pq.top();
            pq.pop();
            ans += a + b;
            pq.push(a + b);
        }
        cout << ans << endl;
    }
    return 0;
}

code.Java:
import java.util.PriorityQueue;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int M = sc.nextInt();
            PriorityQueue<Integer> pq = new PriorityQueue<>();
            for (int i = 0; i < M; i++) {
                int x = sc.nextInt();
                pq.add(x);
            }
            long ans = 0;
            while (pq.size() > 1) {
                int a = pq.poll();
                int b = pq.poll();
                ans += a + b;
                pq.add(a + b);
            }
            System.out.println(ans);
        }
    }
}

