const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextLine() {
    return lines[idx++];
}

let T = nextInt();
while (T-- > 0) {
    let M = nextInt();
    let arr = nextLine().split(' ').map(x => parseInt(x));
    let pq = [];
    for (let x of arr) {
        pq.push(x);
    }
    pq.sort((a, b) => a - b);
    let ans = 0;
    while (pq.length > 1) {
        let a = pq.shift();
        let b = pq.shift();
        ans += a + b;
        pq.push(a + b);
        pq.sort((a, b) => a - b);
    }
    console.log(ans);
}

